444	// C: #define lisdigit(c)   (testprop(c, DIGITBIT))
445	#[inline]
446	fn is_digit(c: i32) -> bool {
447	    c >= b'0' as i32 && c <= b'9' as i32
448	}
449	
450	// C: #define lisxdigit(c)  (testprop(c, XDIGITBIT))
451	#[inline]
452	fn is_xdigit(c: i32) -> bool {
453	    (c >= b'0' as i32 && c <= b'9' as i32)
454	        || (c >= b'a' as i32 && c <= b'f' as i32)
455	        || (c >= b'A' as i32 && c <= b'F' as i32)
456	}
