459	// ALPHABIT: ASCII letters + '_'
460	#[inline]
461	fn is_lalpha(c: i32) -> bool {
462	    (c >= b'a' as i32 && c <= b'z' as i32)
463	        || (c >= b'A' as i32 && c <= b'Z' as i32)
464	        || c == b'_' as i32
465	}
466	
467	// C: #define lislalnum(c)  (testprop(c, ALPHABIT|DIGITBIT))
468	#[inline]
469	fn is_lalnum(c: i32) -> bool {
470	    is_lalpha(c) || is_digit(c)
471	}
