1526	/// Scan a decimal escape `\ddd` (up to 3 digits); return the byte value.
1527	///
1528	/// # C source
1529	/// ```c
1530	/// // C: static int readdecesc (LexState *ls) {
1531	/// //   int i;
1532	/// //   int r = 0;
1533	/// //   for (i = 0; i < 3 && lisdigit(ls->current); i++) {
1534	/// //     r = 10*r + ls->current - '0';
1535	/// //     save_and_next(ls);
1536	/// //   }
1537	/// //   esccheck(ls, r <= UCHAR_MAX, "decimal escape too large");
1538	/// //   luaZ_buffremove(ls->buff, i);  /* remove read digits from buffer */
1539	/// //   return r;
1540	/// // }
1541	/// ```
1542	fn read_dec_esc(
1543	    state: &mut LuaState,
1544	    ls: &mut LexState,
1545	) -> Result<u32, LuaError> {
1546	    let mut i: usize = 0;
1547	    let mut r: u32 = 0;
1548	
1549	    // C: for (i = 0; i < 3 && lisdigit(ls->current); i++)
1550	    while i < 3 && is_digit(ls.current) {
1551	        // C: r = 10*r + ls->current - '0';
1552	        r = 10 * r + (ls.current as u32 - b'0' as u32);
1553	        // C: save_and_next(ls)
1554	        save_and_next(ls, state)?;
1555	        i += 1;
1556	    }
