1558	    // C: esccheck(ls, r <= UCHAR_MAX, "decimal escape too large")
1559	    // UCHAR_MAX = 255 = u8::MAX
1560	    esc_check(state, ls, r <= u8::MAX as u32, b"decimal escape too large")?;
1561	
1562	    // C: luaZ_buffremove(ls->buff, i)
1563	    ls.buff.truncate_by(i);
1564	    Ok(r)
1565	}
