1717	// C: static int llex (LexState *ls, SemInfo *seminfo)
1718	/// Core lexer dispatch: consume and return the next raw token kind.
1719	///
1720	/// This is the heart of the lexer: a large `for`-`switch` loop that classifies
1721	/// the current character and dispatches to the appropriate scanner.
1722	///
1723	/// # C source (see llex.c lines 445-562 for full listing)
1724	fn llex(
1725	    state: &mut LuaState,
1726	    ls: &mut LexState,
1727	    seminfo: &mut TokenValue,
1728	) -> Result<i32, LuaError> {
1729	    // C: luaZ_resetbuffer(ls->buff)
1730	    // macros.tsv: luaZ_resetbuffer → buf.clear()
1731	    ls.buff.clear();
1732	
1733	    loop {
1734	        match ls.current {
1735	            // C: case '\n': case '\r': { inclinenumber(ls); break; }
1736	            c if c == b'\n' as i32 || c == b'\r' as i32 => {
1737	                inc_line_number(ls, state)?;
1738	            }
1739	
1740	            // C: case ' ': case '\f': case '\t': case '\v': { next(ls); break; }
1741	            c if c == b' ' as i32
1742	                || c == b'\x0C' as i32
1743	                || c == b'\t' as i32
1744	                || c == b'\x0B' as i32 =>
1745	            {
1746	                advance(ls);
1747	            }
1748	
1749	            // C: case '-': { '-' or '--' comment }
1750	            c if c == b'-' as i32 => {
1751	                advance(ls); // C: next(ls)
1752	                if ls.current != b'-' as i32 {
1753	                    return Ok(b'-' as i32);
1754	                }
1755	                // C: /* else is a comment */ next(ls)
1756	                advance(ls);
1757	
1758	                if ls.current == b'[' as i32 {
1759	                    // C: long comment?
1760	                    let sep = skip_sep(state, ls)?;
1761	                    // C: luaZ_resetbuffer(ls->buff)
1762	                    ls.buff.clear();
1763	                    if sep >= 2 {
1764	                        // C: read_long_string(ls, NULL, sep)
1765	                        read_long_string(state, ls, None, sep)?;
1766	                        ls.buff.clear(); // C: luaZ_resetbuffer after call
1767	                        continue;
1768	                    }
1769	                }
1770	                // C: short comment — skip until end of line
1771	                while !curr_is_newline(ls) && ls.current != EOZ {
1772	                    advance(ls);
1773	                }
1774	                // loop continues (no token emitted for comments)
1775	            }
1776	
1777	            // C: case '[': { long string or simply '[' }
1778	            c if c == b'[' as i32 => {
1779	                let sep = skip_sep(state, ls)?;
1780	                if sep >= 2 {
