1835	                    return Ok(TK_NE); // C: '~='
1836	                }
1837	                return Ok(b'~' as i32);
1838	            }
1839	
1840	            // C: case ':':
1841	            c if c == b':' as i32 => {
1842	                advance(ls);
1843	                if check_next1(ls, b':' as i32) {
1844	                    return Ok(TK_DBCOLON); // C: '::'
1845	                }
1846	                return Ok(b':' as i32);
1847	            }
