pub struct Token {
    // C: int token;
    pub kind: i32,
    // C: SemInfo seminfo;
    pub value: TokenValue,
}

impl Token {
    /// Construct a token with no semantic value.
    pub fn new(kind: i32) -> Self {
        Token { kind, value: TokenValue::None }
