// TODO(port): replace with state.intern_str(bytes) once LuaState gains that
// method (from lua_vm::string::new_lstr wired in Phase B).
// TODO_ARCH(phase-b-reconcile): canonical LuaString is constructed via
// from_bytes; once LuaState::intern_str is wired, route through there instead.
fn intern_str_stub(
    _state: &mut LuaState,
    bytes: &[u8],
) -> Result<GcRef<LuaString>, LuaError> {
    Ok(Rc::new(LuaString::from_bytes(bytes.to_vec())))
}

/// Result of converting a byte string to a Lua number.
/// TODO(port): replace with the real `LuaValue` enum variants from lua-types (Phase B).
enum NumResult {
    Int(i64),
    Float(f64),
}

// TODO(port): replace with lua_vm::object::str2num(bytes) in Phase B.
// The real implementation handles hex floats (0x1.8p+1), integer overflow, etc.
fn str2num_stub(bytes: &[u8]) -> Option<NumResult> {
    // Strip NUL bytes that may have been saved by the lexer
    let s = bytes.iter().position(|&b| b == 0)
        .map(|n| &bytes[..n])
        .unwrap_or(bytes);

    // Attempt integer parse first (decimal and hex)
    let as_str = std::str::from_utf8(s).ok()?;
    let as_str = as_str.trim();

    // Hex integer: 0x...
    if let Some(hex) = as_str.strip_prefix("0x").or_else(|| as_str.strip_prefix("0X")) {
        if let Ok(v) = i64::from_str_radix(hex, 16) {
            return Some(NumResult::Int(v));
        }
        // Could be a hex float — fall through to float parse
    }

    // Decimal integer
    if let Ok(v) = as_str.parse::<i64>() {
        return Some(NumResult::Int(v));
    }

    // Float (including hex float via standard parse on some platforms)
    if let Ok(v) = as_str.parse::<f64>() {
        return Some(NumResult::Float(v));
    }

    None
}

// TODO(port): replace with lua_vm::object::hex_value(c) in Phase B.
fn hex_value_stub(c: i32) -> u32 {
    match c {
        c if c >= b'0' as i32 && c <= b'9' as i32 => (c - b'0' as i32) as u32,
        c if c >= b'a' as i32 && c <= b'f' as i32 => (c - b'a' as i32 + 10) as u32,
        c if c >= b'A' as i32 && c <= b'F' as i32 => (c - b'A' as i32 + 10) as u32,
        _ => 0,
    }
}

// TODO(port): replace with lua_vm::object::utf8_esc_encode(codepoint) in Phase B.
// Returns a small Vec<u8> of 1-4 bytes.
fn utf8_encode_stub(codepoint: u32) -> Vec<u8> {
    let mut buf = Vec::with_capacity(4);
    if codepoint < 0x80 {
        buf.push(codepoint as u8);
    } else if codepoint < 0x800 {
        buf.push(0xC0 | (codepoint >> 6) as u8);
        buf.push(0x80 | (codepoint & 0x3F) as u8);
    } else if codepoint < 0x10000 {
        buf.push(0xE0 | (codepoint >> 12) as u8);
        buf.push(0x80 | ((codepoint >> 6) & 0x3F) as u8);
        buf.push(0x80 | (codepoint & 0x3F) as u8);
    } else {
        buf.push(0xF0 | (codepoint >> 18) as u8);
        buf.push(0x80 | ((codepoint >> 12) & 0x3F) as u8);
        buf.push(0x80 | ((codepoint >> 6) & 0x3F) as u8);
        buf.push(0x80 | (codepoint & 0x3F) as u8);
    }
    buf
}

